#include <Wire.h>
#include <LiquidCrystal_I2C.h>
#include <DHT.h>

int currentState;

int secondCurrentState;

int noteDuration = 0.5;

int NOTEC4 = 31;

int micValue;

int action;

int maxActions = 4;

LiquidCrystal_I2C lcd(0x27, 16, 2); 

unsigned long lastMillis = 0;
unsigned long buzzMillis = 0;

bool buzzing = false;

bool gameStarted = false;
bool completed = false;
bool generatedAction = false;
bool failed = false;

float time_limit = 4000;
float buzz_limit = 1000;

float tempInitial;

DHT dht(2, DHT11);

void setup() {
  Serial.begin(9600);

  pinMode(8, OUTPUT);
  pinMode(11, INPUT);
  pinMode(10, OUTPUT);

  tone(10, NOTEC4, noteDuration);
  delay(1000);
  noTone(10);

  lcd.init();
  lcd.backlight();
  lcd.setCursor(0, 0);
  lcd.print("PRESS ANY BUTTON TO BEGIN.");

  digitalWrite(8, HIGH);

  dht.begin();
}

void loop(){
  unsigned long currentMillis = millis();

  currentState = digitalRead(11);
  secondCurrentState = digitalRead(12);

  micValue = digitalRead(13);

  if (gameStarted) {
    if (currentMillis - lastMillis >= time_limit) {
      lastMillis = currentMillis;
      failed = true;
    }
  }
  else {
    lastMillis = currentMillis;
  }

  if (buzzing) {
    if (currentMillis - buzzMillis >= buzz_limit) {
      buzzMillis = currentMillis;
      buzzing = false;
      noTone(10);
    }
  }
  else {
    buzzMillis = currentMillis;
  }

  if (!gameStarted) {
    if (currentState == LOW || secondCurrentState == LOW) {
      gameStarted = true;
    }
  }
  else {
    if (!generatedAction) {
        tone(10, NOTEC4, noteDuration);
        buzzing = true;

      digitalWrite(8, LOW);

      generatedAction = true;
      lcd.clear();

  randomSeed(analogRead(A3));

  action = random(0, maxActions);
  String directions = "";

  switch (action){
    case 0:
      directions = "Press the left button.";
      break;
    case 1:
      directions = "Press the right button.";
      break;
    case 2:
      directions = "Make noise into the mic.";
      break;
    case 3:
      directions = "Cover temp sensor.";
      tempInitial = dht.readTemperature();
      if (isnan(tempInitial)) {
        tempInitial = 12.5;
      }
      break;
  }

  if (directions.length() <= 16) {
    lcd.print(directions);
  }
  else {
    lcd.print(directions.substring(0, 16));
    lcd.setCursor(0, 1);
    lcd.print(directions.substring(16));
  }
    }
    else if (generatedAction && !failed) {
      delay(500);
      switch (action){
      case 0:
        if (currentState == LOW) {
      completed = true;
      }
        break;
      case 1:
        if (secondCurrentState == LOW) {
      completed = true;
      }
        break;
      case 2:
        if (micValue == 1) {
      completed = true;
      }
        break;
      case 3:
        if (tempInitial != dht.readTemperature() && !isnan(dht.readTemperature())) {
      completed = true;
      }
        break;
    }
    }
  }

  if (completed) {
    tone(10, NOTEC4, noteDuration);
    buzzing = true;

    lcd.clear();
    lcd.print("You are Quick");

    delay(1000);

    lcd.clear();
    lcd.print("PRESS ANY BUTTON TO BEGIN");
    completed = false;
    generatedAction = false;
    gameStarted = false;
    failed = false;

    digitalWrite(8, HIGH);
  }

  if (failed) {
    tone(10, NOTEC4, noteDuration);
    buzzing = true;

    lcd.clear();
    lcd.print("Took Too Long");

    delay(1000);

    lcd.clear();
    lcd.print("PRESS ANY BUTTON TO BEGIN");
    failed = false;
    generatedAction = false;
    gameStarted = false;
    completed = false;

    digitalWrite(8, HIGH);
  }
}
